#include<stdio.h>
int main()
{
	long long a,b,c,d,k=0;
	scanf("%lld",&a);
	scanf("%lld",&b);
	scanf("%lld",&c);
	scanf("%lld",&d);
	while(1)
	{
		if(a==1)
		break;
        k+=c*(a%b);
        a=a-a%b;
        if(d<c*(a-a/b))
        {
        	k+=d;
        	a/=b;
		}
		else
		{
			k+=c*(a-1);
			break;
		}
	}
	printf("%lld\n",k);
	return 0;
}

