use std::io;
use std::io::Stdin;
use std::str::FromStr;

fn read_line(stdin : &Stdin, line : &mut String) {
    match stdin.read_line(line) {
        Ok(_) => return,
        Err(msg) => panic!("Could not read line! Message: {}.", msg),
    }
}

fn parse_t<T : FromStr>(s : &str) -> T {
    match s.trim().parse() {
        Ok(y) => y,
        Err(_) => panic!("Could not read from string!"),
    }
}

fn read_t<T : FromStr>(stdin : &Stdin) -> T {
    let mut line = String::new();
    read_line(stdin, &mut line);
    parse_t(&line)
}

fn read_ts<T : FromStr>(stdin : &Stdin, ts : &mut Vec<T>) {
    let mut line = String::new();
    read_line(stdin, &mut line);
    let word_iter = line.split_whitespace();
    for word in word_iter {
        let x = parse_t(word);
        ts.push(x);
    }
}

fn cost_to_one(n : u64, k : u64, a : u64, b : u64) -> u64 {
    let mut c = 0;
    let mut x = n;
    if k == 1 {
        c = (x - 1) * a; 
    } else {
        loop {
            if x < 1 {
                panic!("x is less than 1!");
            } else if x == 1 {
                break;
            } else if x < k {
                c = c + (a * (x - 1));
                x = 1;
            } else {
                let q = x / k;
                let r = x % k;
                let cost_div = b;
                let cost_sub = a * ((q * k) - q);
                if r == 0 {
                    if cost_div <= cost_sub {
                        c = c + cost_div;
                    } else {
                        c = c + cost_sub;
                    }
                    x = q;
                } else {
                    c = c + (r * a);
                    x =  x - r;
                }
            }
        }
    }
    c
}

fn main() {
    let stdin = io::stdin();
    let n = read_t(&stdin);
    let k = read_t(&stdin);
    let a = read_t(&stdin);
    let b = read_t(&stdin);
    println!("{}", cost_to_one(n, k, a, b));
}
